 18→func TestIsOutdated(t *testing.T) {
 19→	tests := []struct {
 20→		current string
 21→		latest  string
 22→		want    bool
 23→		desc    string
 24→	}{
 25→		// Standard semver cases
 26→		{"1.0.0", "1.0.1", true, "patch version bump"},
 27→		{"1.0.0", "1.1.0", true, "minor version bump"},
 28→		{"1.0.0", "2.0.0", true, "major version bump"},
 29→		{"1.0.1", "1.0.0", false, "current is newer"},
 30→		{"2.0.0", "1.9.9", false, "current major is higher"},
 31→		{"1.0.0", "1.0.0", false, "same version"},
 32→
 33→		// v-prefix handling
 34→		{"v1.0.0", "v1.0.1", true, "with v prefix"},
 35→		{"v1.0.0", "1.0.1", true, "mixed v prefix"},
 36→		{"1.0.0", "v1.0.1", true, "mixed v prefix reversed"},
 37→
 38→		// Pre-release versions (semver uses hyphen)
 39→		{"1.0.0-rc1", "1.0.0", true, "prerelease in current"},
 40→		{"1.0.0", "1.0.1-rc1", true, "prerelease in latest is still newer"},
 41→		{"1.0.0-dev-xxx", "1.0.1", false, "dev build skips version check"},
 42→	}
 43→
 44→	for _, tt := range tests {
 45→		t.Run(tt.desc, func(t *testing.T) {
 46→			got := isOutdated(tt.current, tt.latest)
 47→			if got != tt.want {
 48→				t.Errorf("isOutdated(%q, %q) = %v, want %v", tt.current, tt.latest, got, tt.want)
 49→			}
 50→		})
 51→	}
 52→}
