100→// loadCache loads the version check cache from disk.
101→// Returns an error if the file doesn't exist or is corrupted.
102→func loadCache() (*VersionCache, error) {
103→	filePath, err := cacheFilePath()
104→	if err != nil {
105→		return nil, err
106→	}
107→
108→	data, err := os.ReadFile(filePath) //nolint:gosec // cacheFilePath is safe
109→	if err != nil {
110→		return nil, fmt.Errorf("reading cache file: %w", err)
111→	}
112→
113→	var cache VersionCache
114→	if err := json.Unmarshal(data, &cache); err != nil {
115→		return nil, fmt.Errorf("parsing cache: %w", err)
116→	}
117→
118→	return &cache, nil
119→}
