121→// saveCache saves the version check cache to disk.
122→// Uses atomic write semantics (write to temp file, then rename).
123→func saveCache(cache *VersionCache) error {
124→	filePath, err := cacheFilePath()
125→	if err != nil {
126→		return err
127→	}
128→
129→	// Marshal to JSON
130→	data, err := json.MarshalIndent(cache, "", "  ")
131→	if err != nil {
132→		return fmt.Errorf("marshaling cache: %w", err)
133→	}
134→
135→	// Write to temp file first (atomic write)
136→	dir := filepath.Dir(filePath)
137→	tmpFile, err := os.CreateTemp(dir, ".version_check_tmp_")
138→	if err != nil {
139→		return fmt.Errorf("creating temp file: %w", err)
140→	}
141→	defer os.Remove(tmpFile.Name())
142→
143→	if _, err := tmpFile.Write(data); err != nil {
144→		_ = tmpFile.Close() // cleanup on error path
145→		return fmt.Errorf("writing cache: %w", err)
146→	}
147→
148→	if err := tmpFile.Close(); err != nil {
149→		return fmt.Errorf("closing temp file: %w", err)
150→	}
151→
152→	// Rename temp file to final location
153→	//nolint:gosec // G703: filePath is constructed internally, not from user input
154→	if err := os.Rename(tmpFile.Name(), filePath); err != nil {
155→		return fmt.Errorf("renaming cache file: %w", err)
156→	}
157→
158→	return nil
159→}
