161→// fetchLatestVersion fetches the latest version from the GitHub API.
162→// Returns a timeout-safe version check using the configured HTTP timeout.
163→func fetchLatestVersion(ctx context.Context) (string, error) {
164→	// Create a context with timeout for the HTTP request
165→	ctx, cancel := context.WithTimeout(ctx, httpTimeout)
166→	defer cancel()
167→
168→	req, err := http.NewRequestWithContext(ctx, http.MethodGet, githubAPIURL, nil)
169→	if err != nil {
170→		return "", fmt.Errorf("creating request: %w", err)
171→	}
172→
173→	// Set headers to identify as Entire CLI
174→	req.Header.Set("Accept", "application/vnd.github+json")
175→	req.Header.Set("User-Agent", "entire-cli")
176→
177→	client := &http.Client{}
178→	resp, err := client.Do(req) //nolint:gosec // G704: intentional request to GitHub releases API
179→	if err != nil {
180→		return "", fmt.Errorf("fetching release info: %w", err)
181→	}
182→	defer resp.Body.Close()
183→
184→	if resp.StatusCode != http.StatusOK {
185→		return "", fmt.Errorf("unexpected status code: %d", resp.StatusCode)
186→	}
187→
188→	// Read response body (limit to 1MB to prevent memory exhaustion)
189→	body, err := io.ReadAll(io.LimitReader(resp.Body, 1<<20))
190→	if err != nil {
191→		return "", fmt.Errorf("reading response: %w", err)
192→	}
193→
194→	// Parse GitHub release response
195→	version, err := parseGitHubRelease(body)
196→	if err != nil {
197→		return "", fmt.Errorf("parsing release: %w", err)
198→	}
199→
200→	return version, nil
201→}
