203→// parseGitHubRelease parses the GitHub API response and extracts the latest stable version.
204→// Filters out prerelease versions.
205→func parseGitHubRelease(body []byte) (string, error) {
206→	var release GitHubRelease
207→	if err := json.Unmarshal(body, &release); err != nil {
208→		return "", fmt.Errorf("parsing JSON: %w", err)
209→	}
210→
211→	// Skip prerelease versions
212→	if release.Prerelease {
213→		return "", errors.New("only prerelease versions available")
214→	}
215→
216→	// Ensure we have a tag name
217→	if release.TagName == "" {
218→		return "", errors.New("empty tag name")
219→	}
220→
221→	return release.TagName, nil
222→}
