224→// isOutdated compares current and latest versions using semantic versioning.
225→// Returns true if current < latest.
226→func isOutdated(current, latest string) bool {
227→	// Ensure versions have "v" prefix for semver package
228→	if !strings.HasPrefix(current, "v") {
229→		current = "v" + current
230→	}
231→	if !strings.HasPrefix(latest, "v") {
232→		latest = "v" + latest
233→	}
234→
235→	// Skip notification for dev builds (e.g., "1.0.0-dev-xxx").
236→	// These are local development builds and shouldn't trigger update notifications.
237→	// Normal prereleases (e.g., "1.0.0-rc1") should still be compared normally.
238→	if strings.Contains(semver.Prerelease(current), "dev") {
239→		return false
240→	}
241→
